const { Manifold } = api;

// 1. Declare Customizer parameters
const p = api.params({
  sausageLength: { type: 'number', default: 46, min: 30, max: 60, step: 1, label: 'Sausage Length' },
  sausageThickness: { type: 'number', default: 4.2, min: 3.0, max: 6.0, step: 0.1, label: 'Sausage Thickness' },
  mustardWaviness: { type: 'int', default: 6, min: 3, max: 12, label: 'Mustard Waves' },
  mustardThickness: { type: 'number', default: 0.8, min: 0.4, max: 1.5, step: 0.1, label: 'Mustard Thickness' },
  bunColor: { type: 'color', default: '#dca266', label: 'Bun Color' },
  sausageColor: { type: 'color', default: '#c24b38', label: 'Sausage Color' },
  mustardColor: { type: 'color', default: '#eab308', label: 'Mustard Color' },
});

const halfLen = p.sausageLength / 2;

// 2. Bun - elongated capsule scaled for an organic look
const bunHalfLen = halfLen - 3;
const bunS1 = Manifold.sphere(9).translate([0, -bunHalfLen, -1]);
const bunS2 = Manifold.sphere(9).translate([0, bunHalfLen, -1]);
const bunBase = bunS1.add(bunS2).hull().scale([1.3, 1.0, 0.95]);

// Dynamic groove to hollow the bun based on sausage thickness
const grooveRadius = p.sausageThickness + 1.3;
const grooveS1 = Manifold.sphere(grooveRadius).translate([0, -bunHalfLen - 2, 4]);
const grooveS2 = Manifold.sphere(grooveRadius).translate([0, bunHalfLen + 2, 4]);
const groove = grooveS1.add(grooveS2).hull();
const bunRaw = bunBase.subtract(groove);
const bun = api.label(bunRaw, 'bun', { color: p.bunColor });

// 3. Sausage - nested inside the bun's groove
const sausageS1 = Manifold.sphere(p.sausageThickness).translate([0, -halfLen, 1]);
const sausageS2 = Manifold.sphere(p.sausageThickness).translate([0, halfLen, 1]);
const sausageRaw = sausageS1.add(sausageS2).hull();
const sausage = api.label(sausageRaw, 'sausage', { color: p.sausageColor });

// 4. Mustard - a wavy continuous tube draped along the top of the sausage
const mustardSpheres = [];
const points = 80;
const waveAmplitude = 2.2;
const yStart = -halfLen + p.sausageThickness;
const yEnd = halfLen - p.sausageThickness;
const yRange = yEnd - yStart;

for (let i = 0; i <= points; i++) {
  const t = i / points;
  const y = yStart + yRange * t;
  const x = waveAmplitude * Math.sin(t * p.mustardWaviness * 2 * Math.PI);
  const z = 1 + p.sausageThickness - 0.2; // sits exactly on top of sausage, slightly intersecting
  mustardSpheres.push(Manifold.sphere(p.mustardThickness).translate([x, y, z]));
}

const mustardSegments = [];
for (let i = 0; i < mustardSpheres.length - 1; i++) {
  mustardSegments.push(mustardSpheres[i].add(mustardSpheres[i+1]).hull());
}
const mustardRaw = api.expectUnion(mustardSegments, { expectComponents: 1 });
const mustard = api.label(mustardRaw, 'mustard', { color: p.mustardColor });

// 5. Solid union of all components to form a single manifold body
const hotdog = api.expectUnion([bun, sausage, mustard], { expectComponents: 1 });
return hotdog;
